const crypto = require('crypto');
const webhookBody = $('Webhook Trigger').first().json.body;
const headers = $('Webhook Trigger').first().json.headers;
const secret = $('Workflow Constants').first().json.N8N_SHARED_SECRET;

const signature = headers['x-profunda-signature'];
if (!signature) throw new Error('Missing x-profunda-signature header');
if (!webhookBody || typeof webhookBody !== 'object') throw new Error('Missing or invalid webhook body');
if (webhookBody.workflow_key !== 'opportunity_monitor') throw new Error('workflow_key must be opportunity_monitor, got: ' + webhookBody.workflow_key);
if (!webhookBody.run_id) throw new Error('Missing run_id');

const bodyStr = JSON.stringify(webhookBody);
const hmac = crypto.createHmac('sha256', secret).update(bodyStr).digest('hex');
if (hmac !== signature) throw new Error('Invalid HMAC signature');

return [{ json: webhookBody }];

const input = $('Verify Signature').first().json;

const opportunity_id = input.opportunity_id || null;
const since = input.since || null;
if (!opportunity_id && !since) throw new Error('opportunity_monitor requires either opportunity_id or since');

const monitor_urls = Array.isArray(input.monitor_urls) ? input.monitor_urls.slice(0, 6).filter(u => typeof u === 'string' && u.trim()) : [];
const previous_hashes = Array.isArray(input.previous_hashes) ? input.previous_hashes.filter(h => typeof h === 'string').slice(0, 50) : [];

return [{
  json: {
    run_id: input.run_id,
    workflow_key: 'opportunity_monitor',
    opportunity_id,
    since,
    org_id: input.org_id || null,
    org_name: input.org_name || null,
    monitor_urls,
    previous_hashes,
    metro_ids: Array.isArray(input.metro_ids) ? input.metro_ids.slice(0, 20) : []
  }
}];

const validated = $('Validate Input').first().json;
const urls = validated.monitor_urls || [];

if (urls.length === 0) {
  return [{ json: { run_id: validated.run_id, org_id: validated.org_id, changes: [], recommendations: [], crawl_skipped: true, skip_reason: 'No monitor_urls provided' } }];
}

// Output each URL as a separate item for parallel crawl
return urls.map((url, i) => ({
  json: { run_id: validated.run_id, org_id: validated.org_id, url_index: i, url, previous_hashes: validated.previous_hashes }
}));

const validated = $('Validate Input').first().json;
const items = $input.all();

const changes = [];
const crypto = require('crypto');

for (const item of items) {
  const scrape = item.json;
  const markdown = scrape?.data?.markdown || scrape?.markdown || '';
  if (!markdown) continue;

  const hash = crypto.createHash('sha256').update(markdown).digest('hex');
  const url = scrape?.data?.metadata?.sourceURL || item.json.url || '';

  // Check against previous hashes
  const prevHashes = validated.previous_hashes || [];
  if (prevHashes.includes(hash)) continue; // No change

  changes.push({
    url,
    content_hash: hash,
    summary: 'Content changed on ' + url,
    fields_changed: ['page_content'],
    char_count: markdown.length
  });
}

return [{
  json: {
    run_id: validated.run_id,
    workflow_key: 'opportunity_monitor',
    changes,
    recommendations: changes.length > 0 ? [{ type: 'review', message: changes.length + ' page(s) have updated content' }] : [],
    change_count: changes.length
  }
}];

const data = $('Detect Changes').first().json;
const error = data.crawl_error || null;

return [{
  json: {
    run_id: data.run_id,
    workflow_key: 'opportunity_monitor',
    payload: {
      result: error ? null : { changes: data.changes || [], recommendations: data.recommendations || [], change_count: data.change_count || 0 },
      error,
      failed_node: error ? 'Detect Changes' : null
    }
  }
}];
